<script setup>
import {reactive,ref} from 'vue';import {useRoute,useRouter} from 'vue-router';import {useAuthStore} from '../stores/auth';import {submitTradeIn} from '../api/tradeInApi';const auth=useAuthStore(),route=useRoute(),router=useRouter(),saving=ref(false),error=ref(''),success=ref(''),form=reactive({customerName:auth.currentUser?.name||'',customerPhone:auth.currentUser?.phone||'',brand:'',model:'',storageCapacity:'',color:'',imei:'',appearanceCondition:'GOOD',functionCondition:'NORMAL',description:'',expectedPrice:null});async function submit(){if(!auth.isAuthenticated){router.push({path:'/login',query:{redirect:route.fullPath}});return}if(saving.value)return;error.value='';success.value='';saving.value=true;try{const data=await submitTradeIn(form);success.value=`估價申請已送出，申請編號 ${data.tradeInNumber}`;Object.assign(form,{brand:'',model:'',storageCapacity:'',color:'',imei:'',appearanceCondition:'GOOD',functionCondition:'NORMAL',description:'',expectedPrice:null})}catch(e){error.value=e.message}finally{saving.value=false}}</script>
<template><main class="service-page"><section class="service-hero trade-hero"><div class="container-wide"><span class="eyebrow">TRADE-IN PROGRAM</span><h1>舊機不閒置，透明估價延續價值</h1><p>提供規格與外觀功能狀態，由專人檢測報價，完整流程可在會員中心追蹤。</p></div></section><section class="section container-wide service-layout"><div><h2>安心收購流程</h2><div class="trust-points"><article><strong>01</strong><h3>線上申請</h3><p>填寫規格、外觀與功能狀況。</p></article><article><strong>02</strong><h3>檢測報價</h3><p>後台完成檢測並提供透明報價。</p></article><article><strong>03</strong><h3>自主決定</h3><p>會員可在線接受或婉拒報價。</p></article></div></div><form class="card service-form" @submit.prevent="submit"><h2>舊機估價資料</h2><p v-if="error" class="alert alert-error">{{error}}</p><p v-if="success" class="alert alert-success">{{success}}</p><div class="form-grid"><label>聯絡姓名<input v-model.trim="form.customerName" required></label><label>聯絡電話<input v-model.trim="form.customerPhone" required></label><label>品牌<input v-model.trim="form.brand" required></label><label>型號<input v-model.trim="form.model" required></label><label>容量<input v-model.trim="form.storageCapacity" placeholder="例如 128GB"></label><label>顏色<input v-model.trim="form.color"></label><label class="field-full">IMEI（選填）<input v-model.trim="form.imei"></label><label>外觀狀況<select v-model="form.appearanceCondition"><option value="LIKE_NEW">近全新</option><option value="GOOD">良好</option><option value="FAIR">一般使用痕跡</option><option value="DAMAGED">明顯損傷</option></select></label><label>功能狀況<select v-model="form.functionCondition"><option value="NORMAL">功能正常</option><option value="MINOR_ISSUE">部分異常</option><option value="MAJOR_ISSUE">主要功能異常</option></select></label><label>期望價格<input v-model.number="form.expectedPrice" type="number" min="0"></label><label class="field-full">補充說明<textarea v-model.trim="form.description" rows="4" maxlength="2000"></textarea></label></div><button class="button button-primary button-block" :disabled="saving">{{saving?'正在送出…':auth.isAuthenticated?'送出估價申請':'登入後送出申請'}}</button></form></section></main></template>
